+	if strings.TrimSpace(path) == "" {
+		return
+	}
+	expanded := config.ExpandHome(path)
+	if regularFileExists(expanded) {
+		return
+	}
+	result.Warnings = append(result.Warnings, ValidationIssue{
+		Field:   field,
+		Message: fmt.Sprintf("file does not exist: %s", expanded),
+	})
